/**
 * widgetContract.ts
 *
 * The Scraplet Widget Contract v1
 *
 * This defines the boundary between:
 * - Widget logic layer (external JS files, marketplace-compatible)
 * - Widget render layer (React components, deterministic)
 *
 * RULES:
 * 1. Widget scripts emit STATE only - never HTML, never DOM mutations
 * 2. React components own all structure - they consume state and render JSX
 * 3. No dangerouslySetInnerHTML - ever
 * 4. State must be JSON-serialisable (enables snapshot replay)
 */

// ─── Widget State Contract ────────────────────────────────────────────────────

/**
 * Every widget emits this event when its state changes.
 * Widget scripts dispatch this on window.
 *
 * Example:
 *   window.dispatchEvent(new CustomEvent('scraplet:widget:state', {
 *     detail: {
 *       widgetId: 'ticker',
 *       instanceId: 'widget_abc123',
 *       state: { items: ['Welcome!', 'Follow us'], speed: 60 }
 *     }
 *   }));
 */
export interface WidgetStateEvent {
  widgetId: string;
  instanceId: string;
  state: Record<string, any>;
}

export const WIDGET_STATE_EVENT = 'scraplet:widget:state';

/**
 * Widget config is passed to the script via window global.
 * Set BEFORE the script loads.
 *
 * Example:
 *   window.__WIDGET_CONFIG_TICKER__ = {
 *     instanceId: 'widget_abc123',
 *     channel: 'scraplet',
 *     bgColor: '#000',
 *     fontFamily: 'Inter'
 *   };
 */
export interface WidgetConfig {
  instanceId: string;
  [key: string]: any;
}

// ─── Widget Renderer Contract ─────────────────────────────────────────────────

/**
 * Every widget type must register a React renderer.
 * The renderer receives the current state and config and returns JSX.
 *
 * The renderer must be:
 * - Pure (same state + config = same output)
 * - Self-contained (no external DOM queries)
 * - CSS-in-JS or scoped styles only (no global CSS injection)
 */
export interface WidgetRendererProps {
  state: Record<string, any>;
  config: WidgetConfig;
  width: number;
  height: number;
}

export type WidgetRenderer = (props: WidgetRendererProps) => React.ReactElement | null;

/**
 * Widget renderer registry.
 * Maps widgetId → React renderer function.
 */
export const widgetRenderers: Map<string, WidgetRenderer> = new Map();

export function registerWidgetRenderer(widgetId: string, renderer: WidgetRenderer): void {
  widgetRenderers.set(widgetId, renderer);
}

export function getWidgetRenderer(widgetId: string): WidgetRenderer | undefined {
  return widgetRenderers.get(widgetId);
}
